create table if not exists public.canonical_entities (
  id uuid primary key default gen_random_uuid(), tenant_id uuid not null references public.tenants(id) on delete cascade,
  module_key text not null, entity_key text not null, name text not null, description text, status text not null default 'active', is_system boolean not null default false, sort_order integer not null default 0,
  created_at timestamptz not null default now(), updated_at timestamptz not null default now(), created_by uuid references auth.users(id), updated_by uuid references auth.users(id),
  unique(tenant_id, entity_key), constraint canonical_entities_status_check check (status in ('active','inactive','deprecated'))
);
create table if not exists public.canonical_fields (
  id uuid primary key default gen_random_uuid(), tenant_id uuid not null references public.tenants(id) on delete cascade,
  canonical_entity_id uuid not null references public.canonical_entities(id) on delete cascade, field_key text not null, name text not null, description text, data_type text not null,
  is_required boolean not null default false, is_system boolean not null default false, sort_order integer not null default 0,
  created_at timestamptz not null default now(), updated_at timestamptz not null default now(), created_by uuid references auth.users(id), updated_by uuid references auth.users(id),
  unique(canonical_entity_id, field_key), constraint canonical_fields_data_type_check check (data_type in ('text','integer','decimal','boolean','date','datetime','enum','json'))
);
create table if not exists public.field_mappings (
  id uuid primary key default gen_random_uuid(), tenant_id uuid not null references public.tenants(id) on delete cascade,
  data_contract_id uuid not null references public.data_contracts(id) on delete cascade, data_contract_field_id uuid not null references public.data_contract_fields(id) on delete cascade,
  canonical_entity_id uuid not null references public.canonical_entities(id) on delete cascade, canonical_field_id uuid not null references public.canonical_fields(id) on delete cascade,
  mapping_type text not null default 'direct', status text not null default 'draft', notes text,
  created_at timestamptz not null default now(), updated_at timestamptz not null default now(), created_by uuid references auth.users(id), updated_by uuid references auth.users(id),
  unique(data_contract_id, data_contract_field_id), constraint field_mappings_mapping_type_check check (mapping_type in ('direct','default_value','transformed','ignored')), constraint field_mappings_status_check check (status in ('draft','active','inactive','rejected'))
);
create table if not exists public.transformation_rules (
  id uuid primary key default gen_random_uuid(), tenant_id uuid not null references public.tenants(id) on delete cascade,
  field_mapping_id uuid not null references public.field_mappings(id) on delete cascade, rule_type text not null, rule_config jsonb not null default '{}'::jsonb, sort_order integer not null default 0, is_active boolean not null default true,
  created_at timestamptz not null default now(), updated_at timestamptz not null default now(), created_by uuid references auth.users(id), updated_by uuid references auth.users(id),
  constraint transformation_rules_rule_type_check check (rule_type in ('trim','uppercase','lowercase','replace','parse_date','cast_type','default_value','enum_map','numeric_round'))
);
create table if not exists public.validation_rules (
  id uuid primary key default gen_random_uuid(), tenant_id uuid not null references public.tenants(id) on delete cascade,
  canonical_entity_id uuid not null references public.canonical_entities(id) on delete cascade, canonical_field_id uuid references public.canonical_fields(id) on delete cascade,
  rule_type text not null, rule_config jsonb not null default '{}'::jsonb, severity text not null default 'error', is_active boolean not null default true, message text,
  created_at timestamptz not null default now(), updated_at timestamptz not null default now(), created_by uuid references auth.users(id), updated_by uuid references auth.users(id),
  constraint validation_rules_rule_type_check check (rule_type in ('required','min_length','max_length','min_value','max_value','regex','allowed_values','date_format')), constraint validation_rules_severity_check check (severity in ('info','warning','error'))
);

do $$ begin
  alter table public.canonical_entities add constraint canonical_entities_id_tenant_id_key unique (id, tenant_id);
exception when duplicate_object then null; end $$;
do $$ begin alter table public.canonical_fields add constraint canonical_fields_id_tenant_id_key unique (id, tenant_id); exception when duplicate_object then null; end $$;
do $$ begin alter table public.field_mappings add constraint field_mappings_id_tenant_id_key unique (id, tenant_id); exception when duplicate_object then null; end $$;
do $$ begin alter table public.canonical_fields add constraint canonical_fields_entity_tenant_fk foreign key (canonical_entity_id, tenant_id) references public.canonical_entities(id, tenant_id) on delete cascade; exception when duplicate_object then null; end $$;
do $$ begin alter table public.field_mappings add constraint field_mappings_contract_tenant_fk foreign key (data_contract_id, tenant_id) references public.data_contracts(id, tenant_id) on delete cascade; exception when duplicate_object then null; end $$;
do $$ begin alter table public.field_mappings add constraint field_mappings_contract_field_tenant_fk foreign key (data_contract_field_id, tenant_id) references public.data_contract_fields(id, tenant_id) on delete cascade; exception when duplicate_object then null; end $$;
do $$ begin alter table public.field_mappings add constraint field_mappings_entity_tenant_fk foreign key (canonical_entity_id, tenant_id) references public.canonical_entities(id, tenant_id) on delete cascade; exception when duplicate_object then null; end $$;
do $$ begin alter table public.field_mappings add constraint field_mappings_canonical_field_tenant_fk foreign key (canonical_field_id, tenant_id) references public.canonical_fields(id, tenant_id) on delete cascade; exception when duplicate_object then null; end $$;
do $$ begin alter table public.transformation_rules add constraint transformation_rules_mapping_tenant_fk foreign key (field_mapping_id, tenant_id) references public.field_mappings(id, tenant_id) on delete cascade; exception when duplicate_object then null; end $$;
do $$ begin alter table public.validation_rules add constraint validation_rules_entity_tenant_fk foreign key (canonical_entity_id, tenant_id) references public.canonical_entities(id, tenant_id) on delete cascade; exception when duplicate_object then null; end $$;
do $$ begin alter table public.validation_rules add constraint validation_rules_field_tenant_fk foreign key (canonical_field_id, tenant_id) references public.canonical_fields(id, tenant_id) on delete cascade; exception when duplicate_object then null; end $$;

create index if not exists idx_canonical_entities_tenant_id on public.canonical_entities(tenant_id); create index if not exists idx_canonical_entities_entity_key on public.canonical_entities(entity_key); create index if not exists idx_canonical_entities_module_key on public.canonical_entities(module_key); create index if not exists idx_canonical_entities_status on public.canonical_entities(status);
create index if not exists idx_canonical_fields_tenant_id on public.canonical_fields(tenant_id); create index if not exists idx_canonical_fields_canonical_entity_id on public.canonical_fields(canonical_entity_id); create index if not exists idx_canonical_fields_field_key on public.canonical_fields(field_key);
create index if not exists idx_field_mappings_tenant_id on public.field_mappings(tenant_id); create index if not exists idx_field_mappings_data_contract_id on public.field_mappings(data_contract_id); create index if not exists idx_field_mappings_data_contract_field_id on public.field_mappings(data_contract_field_id); create index if not exists idx_field_mappings_canonical_entity_id on public.field_mappings(canonical_entity_id); create index if not exists idx_field_mappings_canonical_field_id on public.field_mappings(canonical_field_id); create index if not exists idx_field_mappings_status on public.field_mappings(status);
create index if not exists idx_transformation_rules_tenant_id on public.transformation_rules(tenant_id); create index if not exists idx_transformation_rules_field_mapping_id on public.transformation_rules(field_mapping_id);
create index if not exists idx_validation_rules_tenant_id on public.validation_rules(tenant_id); create index if not exists idx_validation_rules_canonical_entity_id on public.validation_rules(canonical_entity_id); create index if not exists idx_validation_rules_canonical_field_id on public.validation_rules(canonical_field_id);

create trigger set_canonical_entities_updated_at before update on public.canonical_entities for each row execute function public.set_updated_at();
create trigger set_canonical_fields_updated_at before update on public.canonical_fields for each row execute function public.set_updated_at();
create trigger set_field_mappings_updated_at before update on public.field_mappings for each row execute function public.set_updated_at();
create trigger set_transformation_rules_updated_at before update on public.transformation_rules for each row execute function public.set_updated_at();
create trigger set_validation_rules_updated_at before update on public.validation_rules for each row execute function public.set_updated_at();

alter table public.canonical_entities enable row level security; alter table public.canonical_fields enable row level security; alter table public.field_mappings enable row level security; alter table public.transformation_rules enable row level security; alter table public.validation_rules enable row level security;

drop policy if exists "members can read canonical entities with permission" on public.canonical_entities; create policy "members can read canonical entities with permission" on public.canonical_entities for select to authenticated using (public.is_member_of_tenant(tenant_id) and public.user_has_permission(tenant_id,'core.canonical_entities.view'));
drop policy if exists "members can create canonical entities with permission" on public.canonical_entities; create policy "members can create canonical entities with permission" on public.canonical_entities for insert to authenticated with check (public.is_member_of_tenant(tenant_id) and public.user_has_permission(tenant_id,'core.canonical_entities.create'));
drop policy if exists "members can update canonical entities with permission" on public.canonical_entities; create policy "members can update canonical entities with permission" on public.canonical_entities for update to authenticated using (public.is_member_of_tenant(tenant_id) and public.user_has_permission(tenant_id,'core.canonical_entities.update')) with check (public.is_member_of_tenant(tenant_id) and public.user_has_permission(tenant_id,'core.canonical_entities.update'));
