with permission_seed(key,name,module_key,resource,action,description) as (values
('core.canonical_entities.view','Visualizar entidades canônicas','core','canonical_entities','view','Permite visualizar entidades canônicas.'),('core.canonical_entities.create','Criar entidades canônicas','core','canonical_entities','create','Permite criar entidades canônicas.'),('core.canonical_entities.update','Atualizar entidades canônicas','core','canonical_entities','update','Permite atualizar entidades canônicas.'),
('core.canonical_fields.view','Visualizar campos canônicos','core','canonical_fields','view','Permite visualizar campos canônicos.'),('core.canonical_fields.create','Criar campos canônicos','core','canonical_fields','create','Permite criar campos canônicos.'),('core.canonical_fields.update','Atualizar campos canônicos','core','canonical_fields','update','Permite atualizar campos canônicos.'),
('core.field_mappings.view','Visualizar pareamentos','core','field_mappings','view','Permite visualizar pareamentos de campos.'),('core.field_mappings.create','Criar pareamentos','core','field_mappings','create','Permite criar pareamentos de campos.'),('core.field_mappings.update','Atualizar pareamentos','core','field_mappings','update','Permite atualizar pareamentos de campos.'),
('core.transformation_rules.view','Visualizar regras de transformação','core','transformation_rules','view','Permite visualizar regras de transformação controladas.'),('core.transformation_rules.create','Criar regras de transformação','core','transformation_rules','create','Permite criar regras de transformação controladas.'),('core.transformation_rules.update','Atualizar regras de transformação','core','transformation_rules','update','Permite atualizar regras de transformação controladas.'),
('core.validation_rules.view','Visualizar regras de validação canônica','core','validation_rules','view','Permite visualizar regras de validação canônica.'),('core.validation_rules.create','Criar regras de validação canônica','core','validation_rules','create','Permite criar regras de validação canônica.'),('core.validation_rules.update','Atualizar regras de validação canônica','core','validation_rules','update','Permite atualizar regras de validação canônica.'))
insert into public.permissions (key,name,module_key,resource,action,description) select * from permission_seed on conflict (key) do update set name=excluded.name,module_key=excluded.module_key,resource=excluded.resource,action=excluded.action,description=excluded.description,updated_at=now();
insert into public.role_permissions (tenant_id,role_id,permission_id) select r.tenant_id,r.id,p.id from public.roles r cross join public.permissions p where r.key='owner' and p.key in ('core.canonical_entities.view','core.canonical_entities.create','core.canonical_entities.update','core.canonical_fields.view','core.canonical_fields.create','core.canonical_fields.update','core.field_mappings.view','core.field_mappings.create','core.field_mappings.update','core.transformation_rules.view','core.transformation_rules.create','core.transformation_rules.update','core.validation_rules.view','core.validation_rules.create','core.validation_rules.update') on conflict (tenant_id,role_id,permission_id) do nothing;

with t as (select id from public.tenants where slug='agentlog'), ce as (insert into public.canonical_entities (tenant_id,module_key,entity_key,name,description,status,is_system,sort_order) select id,'transporte','deliveries','Entregas','Entidade canônica inicial para entregas.','active',true,10 from t on conflict (tenant_id,entity_key) do update set name=excluded.name,description=excluded.description,status=excluded.status,is_system=true returning id,tenant_id), entity as (select * from ce union all select c.id,c.tenant_id from public.canonical_entities c join t on t.id=c.tenant_id where c.entity_key='deliveries' limit 1), field_seed(field_key,name,data_type,is_required,sort_order) as (values ('delivery_number','Número da entrega','text',true,10),('customer_document','Documento do cliente','text',true,20),('customer_name','Nome do cliente','text',true,30),('delivery_status','Status da entrega','enum',true,40),('expected_delivery_date','Data prevista','date',false,50),('delivered_at','Data de entrega','datetime',false,60),('total_value','Valor total','decimal',false,70))
insert into public.canonical_fields (tenant_id,canonical_entity_id,field_key,name,data_type,is_required,is_system,sort_order) select e.tenant_id,e.id,f.field_key,f.name,f.data_type,f.is_required,true,f.sort_order from entity e cross join field_seed f on conflict (canonical_entity_id,field_key) do update set name=excluded.name,data_type=excluded.data_type,is_required=excluded.is_required,is_system=true,sort_order=excluded.sort_order;
with t as (select id from public.tenants where slug='agentlog'), ce as (select c.id,c.tenant_id from public.canonical_entities c join t on t.id=c.tenant_id where c.entity_key='deliveries'), dc as (select d.id,d.tenant_id from public.data_contracts d join t on t.id=d.tenant_id where d.entity_key='deliveries' and d.name='Contrato inicial de entregas' order by d.contract_version limit 1)
insert into public.field_mappings (tenant_id,data_contract_id,data_contract_field_id,canonical_entity_id,canonical_field_id,mapping_type,status,notes)
select dc.tenant_id,dc.id,dcf.id,ce.id,cf.id,'direct','draft','Seed controlado Sprint 7: field_key do contrato igual ao field_key canônico.' from dc join ce on ce.tenant_id=dc.tenant_id join public.data_contract_fields dcf on dcf.tenant_id=dc.tenant_id and dcf.data_contract_id=dc.id join public.canonical_fields cf on cf.tenant_id=dc.tenant_id and cf.canonical_entity_id=ce.id and cf.field_key=dcf.field_key where dcf.field_key in ('delivery_number','customer_document','customer_name','delivery_status','expected_delivery_date','delivered_at','total_value') on conflict (data_contract_id,data_contract_field_id) do nothing;
